                            <div onClick="{{ apprHdr.perdiem.onClear }}" style="padding:8px 12px;border-radius:7px;font-size:13px;font-weight:500;color:#1F2430;cursor:pointer" style-hover="background:#F6F7F9">Clear all</div>
